using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class ChurnData
{
    [LoadColumn(0)]
    public float Age { get; set; }

    [LoadColumn(1)]
    public float Income { get; set; }

    [LoadColumn(2)]
    public string Region { get; set; } = string.Empty;

    [LoadColumn(3)]
    public float PurchaseHistory { get; set; }

    [LoadColumn(4)]
    public string Churned { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace ChurnPredictor.Models;

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }

    public float Probability { get; set; }

    public float Score { get; set; }
}

using Microsoft.ML;
using Microsoft.ML.Data;
using ChurnPredictor.Models;

namespace ChurnPredictor.Services;

public class ChurnModelService
{
    private readonly ILogger<ChurnModelService> _logger;

    public ChurnModelService(ILogger<ChurnModelService> logger)
    {
        _logger = logger;
    }

    public string TrainAndSave(string dataPath)
    {
        var mlContext = new MLContext(seed: 42);

        var rawData = mlContext.Data.LoadFromTextFile<ChurnData>(
            dataPath, hasHeader: true, separatorChar: ',');

        // Map "Yes"/"No" string to bool Label column
        var labelMapping = new Dictionary<string, bool> { ["Yes"] = true, ["No"] = false };
        var pipeline = mlContext.Transforms.Conversion.MapValue(
                "Label", labelMapping, inputColumnName: nameof(ChurnData.Churned))
            .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(ChurnData.Region)))
            .Append(mlContext.Transforms.Concatenate("Features",
                nameof(ChurnData.Age), nameof(ChurnData.Income),
                "RegionEncoded", nameof(ChurnData.PurchaseHistory)))
            .Append(mlContext.BinaryClassification.Trainers.FastTree());

        var splitData = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2);

        var model = pipeline.Fit(splitData.TrainSet);

        var predictions = model.Transform(splitData.TestSet);
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);

        _logger.LogInformation("AUC: {AUC:F4}", metrics.AreaUnderRocCurve);
        _logger.LogInformation("F1: {F1:F4}", metrics.F1Score);

        var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
        mlContext.Model.Save(model, rawData.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return modelPath;
    }
}

