using Microsoft.Extensions.ML;
using ChurnPredictor.Models;
using ChurnPredictor.Services;

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddSingleton<ChurnModelService>();

var app = builder.Build();

// Train model at startup
var modelService = app.Services.GetRequiredService<ChurnModelService>();
var csvPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
var modelPath = modelService.TrainAndSave(csvPath);

// Register PredictionEnginePool from the saved model
builder.Services.AddPredictionEnginePool<ChurnData, ChurnPrediction>()
    .FromFile(modelPath);

// Rebuild app to pick up the new services
app = builder.Build();

app.MapGet("/", () => "Hello");

app.MapPost("/predict", (PredictionEnginePool<ChurnData, ChurnPrediction> pool, ChurnRequest request) =>
{
    var input = new ChurnData
    {
        Age = request.Age,
        Income = request.Income,
        Region = request.Region,
        PurchaseHistory = request.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        prediction.PredictedLabel,
        prediction.Probability,
        prediction.Score
    });
});

app.Run();

public record ChurnRequest(float Age, float Income, string Region, float PurchaseHistory);

